import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { NavbarComponent } from '../../components/navbar/navbar.component';
import { ReviewCardComponent } from '../../components/review-card/review-card.component';
import { AuthService } from '../../services/auth.service';
import { Review, ReviewService } from '../../services/review.service';

@Component({
  selector: 'app-my-reviews',
  standalone: true,
  imports: [CommonModule, NavbarComponent, ReviewCardComponent],
  templateUrl: './my-reviews.component.html',
  styleUrl: './my-reviews.component.css'
})
export class MyReviewsComponent implements OnInit {
  reviews: Review[] = [];
  loading = true;
  error: string | null = null;

  constructor(
    private reviewService: ReviewService,
    private authService: AuthService,
    private router: Router
  ) {}

  ngOnInit() {
    const userId = this.authService.getUserId();
    if (!userId) return;

    this.reviewService.getReviewsByUser(userId).subscribe({
      next: (reviews) => {
        this.reviews = reviews;
        this.loading = false;
      },
      error: () => {
        this.error = 'Failed to load reviews';
        this.loading = false;
      }
    });
  }

  deleteReview(reviewId: number) {
    if (!confirm('Delete this review?')) return;

    this.reviewService.deleteReview(reviewId).subscribe({
      next: () => {
        this.reviews = this.reviews.filter(r => r.id !== reviewId);
      },
      error: () => this.error = 'Failed to delete review'
    });
  }

  isOwnReview(review: Review): boolean {
    return review.authorName === this.authService.getFullName();
  }

  createReview() {
    this.router.navigate(['/create-review']);
  }
}
<div class="page-container">
  <app-navbar></app-navbar>

  <div class="page-content">
    <div class="page-header">
      <h1>My Reviews</h1>
      <button class="btn btn-primary" (click)="createReview()">+ Write Review</button>
    </div>

    <div *ngIf="loading" class="loading">Loading reviews...</div>
    <div *ngIf="error" class="error-message">{{ error }}</div>

    <div *ngIf="!loading && reviews.length === 0" class="empty-state">
      <p>You haven't written any reviews yet.</p>
      <button class="btn btn-primary" (click)="createReview()">Write Your First Review</button>
    </div>

    <div *ngIf="!loading && reviews.length > 0" class="reviews-list">
      <div *ngFor="let review of reviews" class="review-wrapper">
        <app-review-card [review]="review"></app-review-card>
        <button
          *ngIf="isOwnReview(review)"
          class="delete-review-btn"
          (click)="deleteReview(review.id)"
        >
          Delete Review
        </button>
      </div>
    </div>
  </div>
</div>
